using System.ComponentModel;
using System.Net;
using System.Text.Json;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
var openAiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// ---------------------------------------------------------------------------
// Tools the agent can invoke
// ---------------------------------------------------------------------------
var notebook = new Notebook();

var tools = new AITool[]
{
    AIFunctionFactory.Create(SearchWeb),
    AIFunctionFactory.Create(notebook.SaveNote),
    AIFunctionFactory.Create(notebook.ReadNotes),
};

// ---------------------------------------------------------------------------
// Chat client setup
// ---------------------------------------------------------------------------
IChatClient client = new OpenAIClient(openAiKey)
    .GetChatClient(model)
    .AsIChatClient();

var chatOptions = new ChatOptions
{
    Tools = [.. tools],
    Temperature = 0.3f,
};

// ---------------------------------------------------------------------------
// Agent loop
// ---------------------------------------------------------------------------
Console.WriteLine("=== Research Agent ===");
Console.WriteLine("Enter a topic to research (or 'quit' to exit):\n");

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("> ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    List<ChatMessage> messages =
    [
        new(ChatRole.System, """
            You are a research agent. When the user gives you a topic:
            1. Search the web for relevant information (make 2-3 searches with
               different queries to get broad coverage).
            2. Save the key findings as notes using the note-taking tool.
            3. Read back all your notes and produce a well-structured summary
               with sections, bullet points, and source URLs where available.
            Be thorough but concise.
            """),
        new(ChatRole.User, $"Research the following topic: {topic}"),
    ];

    Console.WriteLine("\nResearching…\n");

    const int maxIterations = 15;
    for (var i = 0; i < maxIterations; i++)
    {
        var response = await client.GetResponseAsync(messages, chatOptions);

        // Append every response message (including tool-call results) to history.
        messages.AddRange(response.Messages);

        // If the model made tool calls, the library auto-invokes them and
        // appends results. We loop so the model can react to those results.
        if (response.Messages.Any(m => m.Contents.OfType<FunctionCallContent>().Any()))
            continue;

        // Final assistant text — print it.
        var text = response.Messages
            .Where(m => m.Role == ChatRole.Assistant)
            .SelectMany(m => m.Contents.OfType<TextContent>())
            .LastOrDefault()?.Text;

        if (!string.IsNullOrWhiteSpace(text))
        {
            Console.ForegroundColor = ConsoleColor.Green;
            Console.WriteLine(text);
            Console.ResetColor();
        }

        break;
    }

    // Clear notebook for the next query.
    notebook.Clear();
    Console.WriteLine();
}

Console.WriteLine("Goodbye!");
return;

// ===================================================================
// Tool implementations
// ===================================================================

[Description("Search the web for a query and return a summary of the top results.")]
static async Task<string> SearchWeb(
    [Description("The search query string")] string query)
{
    Console.ForegroundColor = ConsoleColor.DarkYellow;
    Console.WriteLine($"  🔍  Searching: \"{query}\"");
    Console.ResetColor();

    try
    {
        // Use DuckDuckGo's HTML search page (no API key required).
        using var http = new HttpClient();
        http.DefaultRequestHeaders.UserAgent.ParseAdd(
            "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

        var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
        var html = await http.GetStringAsync(url);

        // Extract result snippets from the HTML.
        var results = new List<string>();
        var snippetMatches = Regex.Matches(html,
            @"<a[^>]+class=""result__a""[^>]*>(?<title>.*?)</a>.*?" +
            @"<a[^>]+class=""result__snippet""[^>]*>(?<snippet>.*?)</a>.*?" +
            @"<a[^>]+class=""result__url""[^>]*href=""(?<url>[^""]+)""",
            RegexOptions.Singleline);

        foreach (Match m in snippetMatches.Take(5))
        {
            var title   = StripHtml(m.Groups["title"].Value);
            var snippet = StripHtml(m.Groups["snippet"].Value);
            var link    = WebUtility.HtmlDecode(m.Groups["url"].Value);
            results.Add($"- **{title}**\n  {snippet}\n  URL: {link}");
        }

        if (results.Count == 0)
        {
            // Fallback: grab any visible text snippets.
            var textMatches = Regex.Matches(html,
                @"class=""result__snippet""[^>]*>(.*?)</a>",
                RegexOptions.Singleline);
            foreach (Match m in textMatches.Take(5))
                results.Add("- " + StripHtml(m.Groups[1].Value));
        }

        return results.Count > 0
            ? $"Search results for \"{query}\":\n\n" + string.Join("\n\n", results)
            : $"No results found for \"{query}\".";
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}";
    }

    static string StripHtml(string s) =>
        WebUtility.HtmlDecode(Regex.Replace(s, "<.*?>", "")).Trim();
}

// ===================================================================
// Notebook – simple in-memory note-taking tool
// ===================================================================

sealed class Notebook
{
    private readonly List<string> _notes = [];

    [Description("Save a research note. Use this to record key findings from search results.")]
    public string SaveNote(
        [Description("A concise note capturing a key finding")] string note)
    {
        _notes.Add(note);
        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  📝  Note saved ({_notes.Count} total)");
        Console.ResetColor();
        return $"Note saved. You now have {_notes.Count} note(s).";
    }

    [Description("Read back all saved research notes.")]
    public string ReadNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        return "Saved notes:\n" + string.Join("\n",
            _notes.Select((n, i) => $"{i + 1}. {n}"));
    }

    public void Clear() => _notes.Clear();
}

